export default function BrandLogo({
  width = 200,
  height = 60,
  dark = true,
  animationType: animTypeProp = "write",
  className = "",
  animated,
}: BrandLogoProps) {
  const animationType = animated === false ? "none" : animTypeProp;
  const fillCol = dark ? "#2D2926" : "#FAF8F6";
  const strokeCol = dark ? "rgba(45, 41, 38, 0.4)" : "rgba(250, 248, 246, 0.4)";

  // SVG dimensions: viewBox="0 0 824 223"
  const svgStyle = {
    width: "100%",
    height: "100%",
    display: "block",
  };

  // 1. "write" animation using a clipping mask that wipes left-to-right
  if (animationType === "write") {
    return (
      <div className={className} style={{ width, height }}>
        <svg
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 824 223"
          style={svgStyle}
        >
          <defs>
            <clipPath id="write-clip">
              <motion.rect
                x="0"
                y="0"
                width="0%"
                height="100%"
                animate={{ width: "100%" }}
                transition={{ duration: 1.8, ease: "easeInOut" }}
              />
            </clipPath>
          </defs>
          <g clipPath="url(#write-clip)" fill={fillCol}>
            {PATHS.map((p, idx) => (
              <path key={idx} d={p.d} transform={p.transform || undefined} />
            ))}
          </g>
        </svg>
      </div>
    );
  }

  // 2. "draw" animation: draws stroke outline first, then fades in fill
  if (animationType === "draw") {
    return (
      <div className={className} style={{ width, height }}>
        <svg
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 824 223"
          style={svgStyle}
        >
          <g>
            {PATHS.map((p, idx) => (
              <motion.path
                key={idx}
                d={p.d}
                transform={p.transform || undefined}
                initial={{ pathLength: 0, fill: "rgba(0,0,0,0)" }}
                animate={{ 
                  pathLength: 1, 
                  fill: fillCol 
                }}
                transition={{
                  pathLength: { duration: 1.5, ease: "easeInOut" },
                  fill: { delay: 1.2, duration: 0.6 }
                }}
                stroke={strokeCol}
                strokeWidth={1}
              />
            ))}
          </g>
        </svg>
      </div>
    );
  }

  // 3. "fade-stagger" animation: segments fade and slide in one after another
  if (animationType === "fade-stagger") {
    return (
      <div className={className} style={{ width, height }}>
        <svg
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 824 223"
          style={svgStyle}
        >
          <g fill={fillCol}>
            {PATHS.map((p, idx) => (
              <motion.path
                key={idx}
                d={p.d}
                transform={p.transform || undefined}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{
                  delay: idx * 0.15,
                  duration: 0.8,
                  ease: [0.215, 0.610, 0.355, 1.000],
                }}
              />
            ))}
          </g>
        </svg>
      </div>
    );
  }

  // 4. "glow-flow" animation: continuous color shimmer moving across the fill
  if (animationType === "glow-flow") {
    const shimmerId = `shimmer-${dark ? "dark" : "light"}`;
    return (
      <div className={className} style={{ width, height }}>
        <svg
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 824 223"
          style={svgStyle}
        >
          <defs>
            <linearGradient id={shimmerId} x1="0%" y1="0%" x2="100%" y2="0%">
              <stop offset="0%" stopColor={fillCol} />
              <motion.stop 
                offset="0%" 
                stopColor={dark ? "#DEB5A0" : "#ffffff"} 
                animate={{ offset: ["0%", "100%", "0%"] }}
                transition={{ duration: 3.5, repeat: Infinity, ease: "linear" }}
              />
              <stop offset="100%" stopColor={fillCol} />
            </linearGradient>
          </defs>
          <g fill={`url(#${shimmerId})`}>
            {PATHS.map((p, idx) => (
              <path key={idx} d={p.d} transform={p.transform || undefined} />
            ))}
          </g>
        </svg>
      </div>
    );
  }

  // 5. "handwritten" animation: sequential stroke drawing with staggering and custom pen style
  if (animationType === "handwritten") {
    const pathConfigs = [
      { delay: 0.0, drawDuration: 1.4, fillDelay: 1.2 }, // Path 0
      { delay: 1.4, drawDuration: 1.4, fillDelay: 2.6 }, // Path 1
      { delay: 2.8, drawDuration: 0.5, fillDelay: 3.1 }, // Path 2
      { delay: 3.3, drawDuration: 0.5, fillDelay: 3.6 }, // Path 3
      { delay: 3.8, drawDuration: 1.6, fillDelay: 5.2 }, // Path 4
      { delay: 5.4, drawDuration: 0.6, fillDelay: 5.8 }  // Path 5
    ];

    return (
      <div className={className} style={{ width, height }}>
        <svg
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 824 223"
          style={svgStyle}
        >
          <g>
            {PATHS.map((p, idx) => {
              const cfg = pathConfigs[idx] || { delay: idx * 0.5, drawDuration: 1.0, fillDelay: idx * 0.5 + 0.8 };
              return (
                <motion.path
                  key={idx}
                  d={p.d}
                  transform={p.transform || undefined}
                  initial={{ pathLength: 0, fill: "rgba(0,0,0,0)" }}
                  animate={{ 
                    pathLength: 1, 
                    fill: "#000000" // Make it black as requested
                  }}
                  transition={{
                    pathLength: { 
                      delay: cfg.delay, 
                      duration: cfg.drawDuration, 
                      ease: "easeInOut" 
                    },
                    fill: { 
                      delay: cfg.fillDelay, 
                      duration: 0.6,
                      ease: "easeOut"
                    }
                  }}
                  stroke="#000000" // Solid black stroke
                  strokeWidth={1.5}
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              );
            })}
          </g>
        </svg>
      </div>
    );
  }

  // Default / "none" static logo
  return (
    <div className={className} style={{ width, height }}>
      <svg
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 824 223"
        style={svgStyle}
        fill={fillCol}
      >
        <g>
          {PATHS.map((p, idx) => (
            <path key={idx} d={p.d} transform={p.transform || undefined} />
          ))}
        </g>
      </svg>
    </div>
  );
}
